+#[test]
+fn wcswcs_finds_substring() {
+    let hay = [
+        b'A' as libc::wchar_t,
+        b'B' as libc::wchar_t,
+        b'C' as libc::wchar_t,
+        0 as libc::wchar_t,
+    ];
+    let needle = [
+        b'B' as libc::wchar_t,
+        b'C' as libc::wchar_t,
+        0 as libc::wchar_t,
+    ];
+    let found = unsafe { wcswcs(hay.as_ptr(), needle.as_ptr()) };
+    assert_eq!(found, unsafe { hay.as_ptr().add(1) as *mut libc::wchar_t });
+}
